const raw = $input.first().json.text || '';

const lines = raw
  .split(/\r?\n/)
  .map(l => l.replace(/\s+/g, ' ').trim())
  .filter(l => l.length > 0);

let studentName = '';
let totalCredits = 0;
const courses = [];

for (const line of lines) {
  let m = line.match(/^(?:Herr|Frau)\s+([A-Za-zÄÖÜäöüß\-\s]+?)(?:,| geboren| Matrikel|$)/);
  if (m) {
    studentName = m[1].trim();
    break;
  }
}

const rowRegex = new RegExp(
  '^(.+?)\\s+' +
  '((?:SS|WS|SoSe|WiSe)\\s?\\d{2}(?:\\s*\\/\\s*\\d{2})?(?:\\s*-\\s*\\d{1,2})?)\\s+' +
  '(\\d[.,]\\d|mit\\s+Erfolg)\\s+' +
  '(?:BE|NB|AN)\\s*\\/?\\s*\\d+\\s+' +
  '(\\d+(?:[.,]\\d+)?)\\s+' +
  '(?:PF|WP|WPF)\\s*$',
  'i'
);

let buffer = '';

for (const line of lines) {
  const candidate = buffer ? `${buffer} ${line}` : line;
  const m = candidate.match(rowRegex);

  if (m) {
    let courseName = m[1].replace(/\s+/g, ' ').trim();

    courseName = courseName
      .replace(/^.*?Wirtschaftsinformatik \(Bachelor\)\s+/i, '')
      .replace(/^.*?PF\/WP\s+/i, '')
      .trim();

    const credits = parseFloat(m[4].replace(',', '.'));

    courses.push({
      courseName,
      semester: m[2]
        .replace(/\s+/g, '')
        .toUpperCase()
        .replace('SOSE', 'SS')
        .replace('WISE', 'WS'),
      grade: m[3].replace('.', ','),
      credits
    });

    totalCredits += credits;
    buffer = '';
  } else {
    if (line.length < 150) {
      buffer = candidate;
      if (buffer.length > 260) buffer = '';
    } else {
      buffer = '';
    }
  }
}

for (const line of lines) {
  const m = line.match(/Summe aller Leistungspunkte:\s*(\d+)/i);
  if (m) {
    totalCredits = Number(m[1]);
    break;
  }
}

return [{
  json: {
    studentName,
    totalCredits,
    courses
  }
}];
